class Solution:
    def numSubarrayBoundedMax(self, nums, left, right):
        """
        :type nums: List[int]
        :type left: int
        :type right: int
        :rtype: int
        """
        def countSubarrays(nums, limit):
            # Count subarrays with max <= limit
            count = 0
            curr_count = 0
            for num in nums:
                if num <= limit:
                    curr_count += 1
                    count += curr_count
                else:
                    curr_count = 0
            return count

        # Subarrays with max in [left, right] = max <= right - max <= left-1
        return countSubarrays(nums, right) - countSubarrays(nums, left - 1)
